class Solution:
    def restoreIpAddresses(self, s: str) -> list[str]:
        n = len(s)
        if n < 4 or n > 12:
            return []

        result = []

        def is_valid_octet(part_str):
            if not (1 <= len(part_str) <= 3):
                return False
            if len(part_str) > 1 and part_str[0] == '0':
                return False
            num = int(part_str)
            return 0 <= num <= 255

        for i in range(1, min(4, n - 2)):
            p1 = s[0:i]
            if not is_valid_octet(p1):
                continue

            for j in range(i + 1, min(i + 4, n - 1)):
                p2 = s[i:j]
                if not is_valid_octet(p2):
                    continue

                for k in range(j + 1, min(j + 4, n)):
                    p3 = s[j:k]
                    if not is_valid_octet(p3):
                        continue

                    p4 = s[k:n]
                    if is_valid_octet(p4):
                        result.append(f"{p1}.{p2}.{p3}.{p4}")
        return result
